import React, { useEffect, useState } from 'react';

function formatoTimer(timeInSeconds) {
  const hours = Math.floor(timeInSeconds / 3600);
  const minutes = Math.floor((timeInSeconds % 3600) / 60);
  const seconds = timeInSeconds % 60;

  return hours > 0
    ? `${hours.toString().padStart(2, '0')}:${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`
    : `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
}

const Timer = () => {
  const [time, setTime] = useState(0);
  const [font, setFont] = useState('Arial');

  useEffect(() => {
    const socket = new WebSocket('ws://localhost:3132?key=McCeAsT6wBw2N8P');

    socket.onopen = () => {
      socket.send('reloadTimer');
    };

    socket.onmessage = (event) => {
      const message = event.data;

      if (message.startsWith('CountTimer')) {
        const timerValue = message.slice('CountTimer'.length);
        const parsedValue = parseInt(timerValue, 10);

        if (!isNaN(parsedValue)) {
          setTime(parsedValue);
        } else {
          console.error('Received invalid timer value:', timerValue);
        }
      } else if (message.startsWith('TimerFont')) {
        const fontValue = message.slice('TimerFont'.length);
        setFont(fontValue);
      }
    };

    return () => {
      socket.close();
    };
  }, []);

  return (
    <div className="w-[790px] h-[130px] mt-[6px] mb-[4px] flex items-center justify-center">
      <div className="inline-flex bg-[#272727] p-5 rounded-lg text-center">
        <p className="timer-text" style={{ fontFamily: font, fontSize: '60px', fontWeight: 'bold' }}>
          {formatoTimer(time)}
        </p>
      </div>
    </div>
  );
};

export default Timer;
